// Fast Date Parser - robust for phone speech like "Monday 9 a.m.", "Monday at 9", "tomorrow 2pm".
// Returns same shape: { output: { requestType, userFormat, requestedTime, startTime, endTime } }
const req = ($json.request || '').toString().trim();
let text = req.toLowerCase();

const cfg = $('Business Config').first().json.business_config || {};
const tz = cfg.timezone || 'America/Toronto';
const now = $now.setZone(tz);

// Normalize common STT punctuation variants.
text = text
  .replace(/a\s*\.\s*m\s*\.?/g, 'am')
  .replace(/p\s*\.\s*m\s*\.?/g, 'pm')
  .replace(/\s+/g, ' ')
  .trim();

const weekdays = {
  sunday: 7, monday: 1, tuesday: 2, wednesday: 3,
  thursday: 4, friday: 5, saturday: 6
};

const months = {
  jan: 1, january: 1, feb: 2, february: 2, mar: 3, march: 3,
  apr: 4, april: 4, may: 5, jun: 6, june: 6, jul: 7, july: 7,
  aug: 8, august: 8, sep: 9, sept: 9, september: 9,
  oct: 10, october: 10, nov: 11, november: 11, dec: 12, december: 12
};

function nextWeekday(target, forceNext = false) {
  let diff = (target - now.weekday + 7) % 7;
  if (diff === 0 || forceNext) diff += 7;
  return now.plus({ days: diff });
}

function formatTime(h24, min) {
  const ap = h24 >= 12 ? 'PM' : 'AM';
  const h = h24 % 12 || 12;
  return `${h}:${String(min).padStart(2, '0')} ${ap}`;
}

function parseTime(input) {
  const t = input.toLowerCase();
  if (/\b(noon|midday)\b/.test(t)) return '12:00 PM';

  // 2pm, 2 pm, 2:30pm, 9 am, 9:00 a.m.
  let m = t.match(/\b(\d{1,2})(?::(\d{2}))?\s*(am|pm)\b/i);
  if (m) {
    let h = Number(m[1]);
    const min = m[2] ? Number(m[2]) : 0;
    const ap = m[3].toLowerCase();
    if (ap === 'pm' && h !== 12) h += 12;
    if (ap === 'am' && h === 12) h = 0;
    return formatTime(h, min);
  }

  // 14:30 / 09:00
  m = t.match(/\b([01]?\d|2[0-3]):([0-5]\d)\b/);
  if (m) {
    return formatTime(Number(m[1]), Number(m[2]));
  }

  // "Monday 9", "Monday at 9", "tomorrow 10", "at 3".
  // For auto shops, bare 8-11 is AM, bare 12 is PM, bare 1-5 is PM.
  m = t.match(/(?:\bat\s+|\b(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday|today|tomorrow)\b\s*,?\s*)(\d{1,2})(?::([0-5]\d))?\b/);
  if (m) {
    let h = Number(m[1]);
    const min = m[2] ? Number(m[2]) : 0;
    if (h >= 1 && h <= 5) h += 12;
    // 6-11 stays AM, 12 stays noon, 13-23 stays 24h if spoken that way.
    return formatTime(h, min);
  }

  return '';
}

let requestedTime = parseTime(text);
let requestType = requestedTime ? 'specific time' : 'full day';
// Time-of-day preference: afternoon/morning/evening without a specific time
if (!requestedTime) {
  if (/\bafternoon\b/.test(text))                    { requestType = 'time_of_day'; requestedTime = 'afternoon'; }
  else if (/\bmorning\b/.test(text))                 { requestType = 'time_of_day'; requestedTime = 'morning'; }
  else if (/\bevening\b|\btonight\b|after\s+work/.test(text)) { requestType = 'time_of_day'; requestedTime = 'evening'; }
  else if (/\bnoon\b|\bmidday\b|\blunch/.test(text))  { requestType = 'time_of_day'; requestedTime = 'afternoon'; }
}
let d = now;
let explicitWeekend = false;
let matchedDate = false;

if (/\btomorrow\b/.test(text)) {
  d = now.plus({ days: 1 });
  matchedDate = true;
} else if (/\btoday\b/.test(text)) {
  d = now;
  matchedDate = true;
} else if (/\bnext week\b/.test(text)) {
  d = nextWeekday(1, true);
  matchedDate = true;
} else {
  for (const [name, num] of Object.entries(weekdays)) {
    const re = new RegExp(`\\b(next\\s+|this\\s+)?${name}\\b`);
    const m = text.match(re);
    if (m) {
      explicitWeekend = num >= 6;
      d = nextWeekday(num, (m[1] || '').trim() === 'next');
      matchedDate = true;
      break;
    }
  }

  if (!matchedDate) {
    let m = text.match(/\b(\d{4})-(\d{1,2})-(\d{1,2})\b/);
    if (m) {
      d = now.set({ year: Number(m[1]), month: Number(m[2]), day: Number(m[3]) });
      matchedDate = true;
    } else {
      m = text.match(/\b(january|jan|february|feb|march|mar|april|apr|may|june|jun|july|jul|august|aug|september|sept|sep|october|oct|november|nov|december|dec)\s+(\d{1,2})(?:st|nd|rd|th)?(?:,?\s*(\d{4}))?\b/);
      if (m) {
        d = now.set({ year: m[3] ? Number(m[3]) : now.year, month: months[m[1]], day: Number(m[2]) });
        if (d < now.startOf('day')) d = d.plus({ years: 1 });
        matchedDate = true;
      }
    }
  }
}

// If no date was said, assume next business day so the workflow does not accidentally book today.
if (!matchedDate) {
  d = now.plus({ days: 1 });
}

if (!explicitWeekend && (d.weekday === 6 || d.weekday === 7)) {
  while (d.weekday === 6 || d.weekday === 7) d = d.plus({ days: 1 });
}

const start = d.set({ hour: 9, minute: 0, second: 0, millisecond: 0 });
const end = d.set({ hour: 17, minute: 0, second: 0, millisecond: 0 });

return {
  json: {
    output: {
      requestType,
      userFormat: req,
      requestedTime,
      startTime: start.toISO(),
      endTime: end.toISO()
    }
  }
};

// Duration-aware availability processor. Checks real usable gaps only.
// Shows only example times, not the full list, so the caller does not hear a huge schedule.
const calendarEvents = $input.all().map(item => item.json);
const ctx = $('Set Data').first().json || {};
const cfg = $('Business Config').first().json.business_config || {};
const tz = ctx.timezone || cfg.timezone || 'America/Toronto';

const requestType = ctx.requestType || ctx.requestedType || 'full day';
const userFormat = ctx.userFormat || 'that day';
const requestedTime = ctx.requestedTime || '';
const startTime = ctx.startTime;
const endTime = ctx.endTime;
const estimatedMinutes = Math.max(15, Number(ctx.estimatedMinutes || 90) || 90);
const durationHours = estimatedMinutes / 60;

function parseHours() {
  const oh = (cfg.opening_hours || '09:00-17:00').toString();
  const m = oh.match(/(\d{1,2}):(\d{2})\s*-\s*(\d{1,2}):(\d{2})/);
  if (!m) return { open: 9, close: 17 };
  return { open: Number(m[1]) + Number(m[2]) / 60, close: Number(m[3]) + Number(m[4]) / 60 };
}
const { open, close } = parseHours();

// ── Closed-day guard (driven by cfg.operating_days, e.g. "Mon-Fri") ──
function allowedWeekdays() {
  const od = (cfg.operating_days || 'Mon-Fri').toString().toLowerCase();
  const names = { mon:1, tue:2, wed:3, thu:4, fri:5, sat:6, sun:7 };
  const m = od.match(/([a-z]{3})[a-z]*\s*-\s*([a-z]{3})/);
  if (m && names[m[1]] && names[m[2]]) {
    const set = new Set(); let d = names[m[1]];
    while (true) { set.add(d); if (d === names[m[2]]) break; d = d % 7 + 1; }
    return set;
  }
  const listed = od.match(/[a-z]{3}/g);
  if (listed) { const s = new Set(listed.map(x => names[x]).filter(Boolean)); if (s.size) return s; }
  return new Set([1, 2, 3, 4, 5]);
}
{
  const reqDay = DateTime.fromISO(startTime, { zone: tz });
  if (reqDay.isValid && !allowedWeekdays().has(reqDay.weekday)) {
    return { json: {
      message: `We're closed on ${reqDay.toFormat('cccc')}s. We're open ${cfg.operating_days || 'Monday to Friday'}, ${cfg.opening_hours || '9 to 5'}. What other day works for you?`,
      scenario: 3, available: false, checkNextDay: false,
      userFormat, requestedTime, requestType, startTime, endTime,
      confirmedStartTime: null, confirmedEndTime: null,
      estimatedMinutes, service: ctx.service || '',
      nextDayStartTime: null, nextDayEndTime: null,
      note: 'Requested day is outside operating days.'
    }};
  }
}

function dtToDecimal(dateTimeStr) {
  const d = DateTime.fromISO(dateTimeStr, { setZone: true }).setZone(tz);
  return d.hour + d.minute / 60;
}
const EPSILON = 0.001;

function timeToDecimal(timeStr) {
  if (!timeStr) return null;
  const t = String(timeStr)
    .replace(/\u00a0|\u2009|\u202f/g, ' ')
    .replace(/a\s*\.\s*m\s*\.?/gi, 'AM')
    .replace(/p\s*\.\s*m\s*\.?/gi, 'PM')
    .replace(/\s+/g, ' ').trim();
  const m = t.match(/^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$/i);
  if (!m) return null;
  let h = Number(m[1]);
  const min = m[2] ? Number(m[2]) : 0;
  const pm = m[3].toUpperCase() === 'PM';
  if (pm && h !== 12) h += 12;
  if (!pm && h === 12) h = 0;
  return h + min / 60;
}
function formatTime(decimalHour) {
  let total = Math.round(decimalHour * 60);
  let h = Math.floor(total / 60);
  let m = total % 60;
  const period = h >= 12 ? 'PM' : 'AM';
  let display = h % 12;
  if (display === 0) display = 12;
  return m === 0 ? `${display} ${period}` : `${display}:${String(m).padStart(2, '0')} ${period}`;
}
function formatDateNice(iso) {
  return DateTime.fromISO(iso, { zone: tz }).setZone(tz).toFormat('cccc, LLL d');
}
function extractDay(format) {
  const s = String(format || '')
    .replace(/,?\s*\d{1,2}(:\d{2})?\s*(a\.?m\.?|p\.?m\.?)\.?/ig, '')
    .replace(/\bat\b/ig, '')
    .trim();
  return s || formatDateNice(startTime);
}
function nextWeekday(iso) {
  let d = DateTime.fromISO(iso, { zone: tz }).setZone(tz).plus({ days: 1 });
  while (d.weekday === 6 || d.weekday === 7) d = d.plus({ days: 1 });
  return d.toISO();
}
function buildIsoForDecimal(dayIso, decimalHour) {
  const base = DateTime.fromISO(dayIso, { zone: tz }).setZone(tz);
  const hours = Math.floor(decimalHour);
  const minutes = Math.round((decimalHour - hours) * 60);
  return base.set({ hour: hours, minute: minutes, second: 0, millisecond: 0 }).toISO();
}

const busyBlocks = [];
for (const event of calendarEvents) {
  if (!event.start?.dateTime || !event.end?.dateTime) continue;
  const s = dtToDecimal(event.start.dateTime);
  const e = dtToDecimal(event.end.dateTime);
  if (e <= open || s >= close) continue;
  busyBlocks.push({ start: Math.max(open, s), end: Math.min(close, e) });
}
busyBlocks.sort((a, b) => a.start - b.start);

const availableSlots = [];
let cur = open;
for (const b of busyBlocks) {
  if (cur < b.start) availableSlots.push({ start: cur, end: b.start });
  cur = Math.max(cur, b.end);
}
if (cur < close) availableSlots.push({ start: cur, end: close });

const usableSlots = availableSlots.filter(s => (s.end - s.start) >= durationHours);

// ── Time-of-day preference filter (afternoon / morning / evening) ──
const TOD_WINDOWS = {
  morning:   { from: open,               to: Math.min(12, close) },
  afternoon: { from: Math.max(12, open), to: close },
  evening:   { from: Math.max(15, open), to: close }
};
const todKey = (requestedTime || '').toLowerCase();
const isTOD = requestType === 'time_of_day' && TOD_WINDOWS[todKey];
let preferredSlots = usableSlots;
if (isTOD) {
  const w = TOD_WINDOWS[todKey];
  preferredSlots = usableSlots
    .map(s => ({ start: Math.max(s.start, w.from), end: Math.min(s.end, w.to) }))
    .filter(s => (s.end - s.start) >= durationHours);
}

function formatSlots(slots) {
  const starts = slots.slice(0, 3).map(s => formatTime(s.start));
  if (starts.length === 0) return '';
  if (starts.length === 1) return starts[0];
  if (starts.length === 2) return `${starts[0]} or ${starts[1]}`;
  return `${starts[0]}, ${starts[1]}, or ${starts[2]}`;
}

let response;
let confirmedStartTime = null;
let confirmedEndTime = null;
let available = false;

if (requestType === 'specific time' && requestedTime) {
  const requestedDecimal = timeToDecimal(requestedTime);
  const ok = requestedDecimal !== null && usableSlots.some(s => requestedDecimal >= s.start - EPSILON && requestedDecimal + durationHours <= s.end + EPSILON);

  if (ok) {
    confirmedStartTime = buildIsoForDecimal(startTime, requestedDecimal);
    confirmedEndTime = DateTime.fromISO(confirmedStartTime, { zone: tz }).plus({ minutes: estimatedMinutes }).toISO();
    available = true;
    response = {
      scenario: 1,
      message: `Yes, ${formatDateNice(startTime)} at ${requestedTime} is available.`,
      checkNextDay: false
    };
  } else if (usableSlots.length) {
    response = {
      scenario: 2,
      message: `${requestedTime} is not available for a ${estimatedMinutes}-minute appointment. On ${extractDay(userFormat)}, we still have openings. For example, we can do ${formatSlots(usableSlots)}. Would any of those work?`,
      checkNextDay: false
    };
  } else {
    response = {
      scenario: 3,
      message: `${extractDay(userFormat)} is fully booked for a ${estimatedMinutes}-minute appointment.`,
      checkNextDay: true
    };
  }
} else {
  if (isTOD && preferredSlots.length) {
    response = {
      scenario: 1,
      message: `We have ${todKey} openings on ${extractDay(userFormat)}. For example, we can do ${formatSlots(preferredSlots)}. What time works best?`,
      checkNextDay: false
    };
  } else if (isTOD && usableSlots.length) {
    response = {
      scenario: 2,
      message: `The ${todKey} is fully booked on ${extractDay(userFormat)}, but we still have other openings — for example ${formatSlots(usableSlots)}. Would any of those work?`,
      checkNextDay: false
    };
  } else if (usableSlots.length) {
    response = {
      scenario: 1,
      message: `We have openings on ${extractDay(userFormat)}. For example, we can do ${formatSlots(usableSlots)}. What time works best?`,
      checkNextDay: false
    };
  } else {
    response = {
      scenario: 3,
      message: `${extractDay(userFormat)} is fully booked for a ${estimatedMinutes}-minute appointment.`,
      checkNextDay: true
    };
  }
}

// Cap the next-day search loop at 4 extra days
const _hops = Number(ctx._hops || 0);
if (response.checkNextDay && _hops >= 4) {
  response.checkNextDay = false;
  response.message += ' We appear to be fully booked for the next few days — would another week work?';
}

return {
  json: {
    _hops,
    message: response.message,
    scenario: response.scenario,
    available,
    checkNextDay: response.checkNextDay,
    userFormat,
    requestedTime,
    requestType,
    startTime,
    endTime,
    confirmedStartTime,
    confirmedEndTime,
    estimatedMinutes,
    service: ctx.service || '',
    nextDayStartTime: response.checkNextDay ? nextWeekday(startTime) : null,
    nextDayEndTime: response.checkNextDay ? nextWeekday(endTime) : null,
    note: 'Available times shown are examples, not the full list.'
  }
};

// ── Duration resolver (Option C architecture) ──────────────────────
// Resolves service duration from the Services catalog when the AI did
// not supply estimatedMinutes. Mirrors the estimate branch matcher —
// deliberate duplication, recorded in DECISIONS.md. Falls back to the
// caller-supplied default (90) when the catalog is unavailable or the
// service cannot be matched — exactly the pre-V26.7 behavior.
function resolveDurationMinutes(readNode, svcText, catText, detText, fallbackMin) {
  let services = [];
  try {
    services = $(readNode).all().map(i => i.json).filter(r => r && r.key).map(r => ({
      key: (r.key || '').toLowerCase().trim(),
      label: r.label || r.service_name || r.key,
      duration_minutes: parseInt(r.duration_minutes || r.duration || 90),
      starting_at: parseFloat(r.starting_at || r.price || 0)
    }));
  } catch(e) {}
  if (!services.length) return fallbackMin;
  const _svc = (svcText || '').toString().trim();
  const _cat = (catText || '').toString().trim().toLowerCase();
  const _det = (detText || '').toString().trim();
  if (!_svc && !_cat && !_det) return fallbackMin;
function normaliseKey(str) {
  // Convert any variation to a comparable slug: spaces/hyphens -> underscore, lowercase
  return (str || '').toLowerCase().replace(/[\s\-]+/g, '_').replace(/[^a-z0-9_]/g, '').trim();
}
const STOP = new Set([
  'and','or','the','for','with','from','each','per','this','that','both','new',
  'all','any','are','was','were','has','have','had','its','our','their',
  'at','be','by','do','go','is','it','me','my','no','of','on','so','to','up','us','we',
  'an','as','in','if','he','hi','ok','oh',
  'service','servicing','services','repair','repairs','fix','fixed','fixing',
  'need','needs','needed','want','wants','wanted','car','vehicle','truck',
  'please','some','something','look','looking','check','job','work','get','got',
]);

function keep(w) {
  return ((w.length === 2 && /^[a-z0-9]+$/.test(w) && /[a-z]/.test(w)) || w.length > 2) && !STOP.has(w);
}

function stem(w) {
  let prev;
  do {
    prev = w;
    w = w.replace(/ies$/, 'y')
         .replace(/tions?$/, 'te')
         .replace(/ments?$/, '')
         .replace(/ings?$/, '')
         .replace(/ness$/, '')
         .replace(/able$/, '')
         .replace(/ible$/, '')
         .replace(/ers?$/, '')
         .replace(/eds?$/, '')
         .replace(/s$/, '')     // s$ BEFORE es$ — "axles"→"axle", not "axl"
         .replace(/es$/, '');
  } while (w !== prev && w.length > 2);
  return w;
}
function matchService(key, category, rawText) {
  const search = [key, category, rawText].join(' ').toLowerCase();

  // ── Pass 0: unambiguous keyword overrides ────────────────────────
  const hasSynthetic = /\bsynthetic\b/i.test(search) && /\boil\b/i.test(search);
  const hasRotor     = /\brotor/i.test(search) && !/\b(?:no|not|without)\s+rotor/i.test(search);
  // Both-axle phrasing: front+rear, all around, all four, both axles, four rotors/wheels/corners
  const allAround    = /\b(?:front[\s\S]{0,20}rear|rear[\s\S]{0,20}front|all\s+(?:around|four)|both\s+axles?|four\s+(?:rotors?|wheels?|corners?))\b/i.test(search);
  // front+rear → brakes ONLY when brake context present (not for axle replacement)
  const hasFrontRear = allAround && /\bbrak/i.test(search);
  if (hasSynthetic) { const s = services.find(s => s.key === 'oil_change_synthetic'); if (s) return s; }
  if (hasRotor && allAround) {
    // All-four bundle if the sheet has it; per-axle row otherwise
    const s = services.find(s => s.key === 'brake_rotors_all') || services.find(s => s.key === 'brake_rotors');
    if (s) return s;
  }
  if (hasRotor)     { const s = services.find(s => s.key === 'brake_rotors');         if (s) return s; }
  if (hasFrontRear) { const s = services.find(s => s.key === 'brakes');               if (s) return s; }

  // ── Pass 1: exact normalised key match ───────────────────────────
  const normKey = normaliseKey(key);
  const normCat = normaliseKey(category);
  const exact = services.find(s =>
    s.key === normKey || s.key === normCat ||
    s.key === key     || s.key === category
  );
  if (exact) return exact;

  // ── Build stemmed search-word set; remove negated words ──────────
  const tokens = search.split(/[\W_]+/).filter(keep);
  const negated = new Set();
  for (const m of search.matchAll(/\b(?:no|not|without)\s+(\w+)/g)) {
    negated.add(stem(m[1]));
  }
  const searchWords = new Set(tokens.map(stem).filter(w => !negated.has(w)));

  // ── Scoring ───────────────────────────────────────────────────────
  // key word hit = 2pts. Core label word hit = 1pt (+2 rarity bonus when the
  // word appears in at most 2 services' key/core vocabulary — e.g. "axle" only
  // lives in the CV Joint / Axle Shaft row, so "replace front axles" finds it).
  // Qualifier words (after "–" or in parentheses, like "– Front" or
  // "(per axle)") = 1pt, no rarity bonus — they describe scope, not the part.
  function splitLabel(label) {
    const parts = String(label || '').toLowerCase().split(/\s[–—]\s|\s-\s|\(/);
    const core = (parts.shift() || '');
    const qual = parts.join(' ');
    return {
      core: core.split(/[\W_]+/).filter(keep).map(stem),
      qual: qual.split(/[\W_]+/).filter(keep).map(stem)
    };
  }
  // Document frequency over key + core-label words only
  const docFreq = {};
  for (const svc of services) {
    const l = splitLabel(svc.label);
    const ws = new Set([...svc.key.split('_').filter(keep).map(stem), ...l.core]);
    for (const w of ws) docFreq[w] = (docFreq[w] || 0) + 1;
  }
  let bestScore = 0, bestMatch = null;
  for (const svc of services) {
    const l = splitLabel(svc.label);
    const keyWords = svc.key.split('_').filter(keep).map(stem);
    let score = 0;
    const bonused = new Set();
    for (const w of keyWords) if (searchWords.has(w)) {
      score += 2;
      if ((docFreq[w] || 0) <= 2 && !bonused.has(w)) { score += 2; bonused.add(w); }
    }
    for (const w of l.core) if (searchWords.has(w)) {
      score += 1;
      if ((docFreq[w] || 0) <= 2 && !bonused.has(w)) { score += 2; bonused.add(w); }
    }
    for (const w of l.qual) if (searchWords.has(w)) score += 1;
    if (score > bestScore || (score === bestScore && bestMatch && svc.starting_at > bestMatch.starting_at)) {
      bestScore = score;
      bestMatch = svc;
    }
  }
  return bestScore >= 2 ? bestMatch : null;
}
  const m = matchService(_cat || _svc, _cat, [_svc, _det].join(' '));
  return (m && Number(m.duration_minutes) >= 15) ? Number(m.duration_minutes) : fallbackMin;
}

// Set Data - Availability context builder
const trigger = $('When Executed by Another Workflow').first().json || {};
const cfg = $('Business Config').first().json.business_config || {};
const tz = cfg.timezone || 'America/Toronto';
// Loop-back support: when re-entered from the availability Code node
// (checkNextDay), input has nextDayStartTime at top level, not $json.output.
// Input source note: 'Read Services - Availability' now sits between the
// date parser and this node, so $json is a catalog row on the first pass.
// The parser output is read by explicit node reference; loop-back items
// (checkNextDay) are detected by their nextDay fields as before.
const isLoop = !!($json && !$json.output && ($json.nextDayStartTime || $json.nextDayEndTime));
const out = isLoop ? {
  requestType: 'full day',
  userFormat: $json.userFormat || '',
  requestedTime: '',
  startTime: $json.nextDayStartTime,
  endTime: $json.nextDayEndTime
} : ($('Fast Date Parser - Availability').first().json.output || {});
const _hops = Number($json._hops || 0) + (isLoop ? 1 : 0);
