// Build busy blocks — skip the appointment being rescheduled to avoid blocking its own slot
const busy = [];
for (const ev of calendarEvents) {
  if (!ev.start?.dateTime || !ev.end?.dateTime) continue;
  if (appointmentId && ev.id === appointmentId) continue;
  const s = dtToDecimal(ev.start.dateTime);
  const e = dtToDecimal(ev.end.dateTime);
  if (s === null || e === null) continue;
  if (e <= open || s >= close) continue;
  busy.push({ start: Math.max(open, s), end: Math.min(close, e) });
}
busy.sort((a, b) => a.start - b.start);

const slots = [];
let cur = open;
for (const b of busy) {
  if (cur < b.start - EPSILON) slots.push({ start: cur, end: b.start });
  cur = Math.max(cur, b.end);
}
if (cur < close - EPSILON) slots.push({ start: cur, end: close });
const usable = slots.filter(s => (s.end - s.start) >= durationHours - EPSILON);

// Prefer confirmedStartTime from get_availability if valid
let rd = timeToDecimal(requestedTime);
let usingConfirmed = false;
if (confirmedStartTime) {
  const cd = dtToDecimal(confirmedStartTime);
  if (cd !== null && cd >= open - EPSILON && cd < close) {
    rd = cd;
    usingConfirmed = true;
  }
}

const ok = rd !== null && usable.some(s => slotFits(s.start, s.end, rd, durationHours));

let scenario, message = '', appointmentStartTime = null, appointmentEndTime = null, appointmentDate = null, appointmentTime = null;

if (ok) {
  scenario = 1;
  let start, end;
  if (usingConfirmed) {
    start = DateTime.fromISO(confirmedStartTime, { setZone: true }).setZone(tz);
    end = confirmedEndTime
      ? DateTime.fromISO(confirmedEndTime, { setZone: true }).setZone(tz)
      : start.plus({ minutes: estimatedMinutes });
  } else {
    const base = DateTime.fromISO(startTime, { zone: tz }).setZone(tz);
    const h = Math.floor(rd), min = Math.round((rd - h) * 60);
    start = base.set({ hour: h, minute: min, second: 0, millisecond: 0 });
    end = start.plus({ minutes: estimatedMinutes });
  }
  appointmentStartTime = start.toISO();
  appointmentEndTime = end.toISO();
  appointmentDate = start.toFormat('cccc, LLL d');
  appointmentTime = start.toFormat('h:mm a');
} else if (!requestedTime && !usingConfirmed && usable.length) {
  scenario = 2;
  message = `I need a specific time to reschedule it. On ${extractDay(userFormat)}, we have openings. For example, we can do ${formatSlots(usable)}. Which one works?`;
} else if (usable.length) {
  scenario = 2;
  message = `${requestedTime || 'That time'} is not available. On ${extractDay(userFormat)}, we still have openings. For example, we can do ${formatSlots(usable)}. Would any of those work?`;
} else {
  scenario = 3;
  message = `${extractDay(userFormat)} is fully booked. Please choose another day or time.`;
}

return { json: {
  scenario, message, requestedTime, userFormat, requestType, startTime, endTime,
  customerName, customerPhone, appointmentId, eventId: appointmentId, estimatedMinutes,
  appointmentStartTime, appointmentEndTime, appointmentDate, appointmentTime,
  _debug: { rd, usingConfirmed, usableCount: usable.length, busyCount: busy.length, open, close }
}};

// Set Data2 - Reschedule context builder
function firstNameOnly(v) {
  const s = (v || '').toString().trim();
  if (!s) return '';
  return s.split(/\s+/)[0];
}

function normalizePhone(v) {
  if (!v) return '';
  const digits = String(v).replace(/[^\d]/g, '');
  if (!digits) return '';
  if (String(v).trim().startsWith('+')) return String(v).trim();
  if (digits.length === 10) return '+1' + digits;
  if (digits.length === 11 && digits.startsWith('1')) return '+' + digits;
  return '+' + digits;
}
function getFirstJson(nodeName) { try { return $(nodeName).first().json || {}; } catch (e) { return {}; } }
const parserOutput = getFirstJson('Fast Date Parser - Reschedule').output || $json.output || {};
const trigger = getFirstJson('When Executed by Another Workflow');
const cfg = getFirstJson('Business Config').business_config || {};
const timezone = cfg.timezone || 'America/Toronto';
const customerName = firstNameOnly(trigger.name || trigger.customerName || '');
// ── Phone resolution — static data is written at call start (setVar webhook)
// and is always available before any tool call fires.
// Order: (1) static data  (2) Sessions sheet  (3) trigger payload
function resolveCallerPhone(sessionNodeName) {
  // 1. Static data — fastest, always written first
  try {
    const sd = $getWorkflowStaticData('global');
    if (sd.caller_phone && sd.stored_at && (Date.now() - sd.stored_at) < 7200000) {
      return sd.caller_phone;
    }
  } catch(e) {}
  // 2. Sessions sheet
  try {
    const rows = $(sessionNodeName).all().map(r => r.json || {}).filter(r => r.caller_phone);
    if (rows.length > 0) {
      rows.sort((a, b) => new Date(b.stored_at || 0) - new Date(a.stored_at || 0));
      return rows[0].caller_phone || '';
    }
  } catch(e) {}
  return '';
}
const customerPhone = normalizePhone(
  resolveCallerPhone('Read Sessions - Reschedule')
  || trigger.caller_phone || trigger.phone || trigger.customerPhone || ''
);
const eventId = trigger.eventId || trigger.appointment_id || trigger.appointmentId || '';
const estimatedMinutes = Math.max(15, Number(trigger.estimatedMinutes || trigger.durationMinutes || 90) || 90);

const confirmedStartTime = trigger.confirmedStartTime || trigger.confirmedStartISO || '';
const confirmedEndTime = trigger.confirmedEndTime || trigger.confirmedEndISO || '';
// Pass the parser's startTime directly — it already encodes the correct requested
// time (e.g. 3 PM). Do NOT replace with a hardcoded 09:00 business-day window;
// that would cause Code4 to always check/book from 9 AM regardless of what the
// caller asked for.
const normalized = {
  startTime: parserOutput.startTime || '',
  endTime: parserOutput.endTime || ''
};
return { json: {
  requestedType: parserOutput.requestType || 'specific time',
  requestType: parserOutput.requestType || 'specific time',
  userFormat: parserOutput.userFormat || trigger.request || '',
  requestedTime: parserOutput.requestedTime || '',
  startTime: normalized.startTime,
  endTime: normalized.endTime,
  customerName,
  customerPhone,
  eventId,
  appointmentId: eventId,
  estimatedMinutes,
  timezone,
  confirmedStartTime,
  confirmedEndTime
} };

// Return reschedule unavailable/needs-time message
const out = $input.first().json || {};
return { json: { success: false, rescheduled: false, message: out.message || 'That time is not available. Please choose another time.' } };

