// Estimate Job Ballpark - reads pricing from Services Google Sheet tab.
// Falls back to Business Config services if sheet is unavailable.

// ROOT-CAUSE FIX: this node runs AFTER 'Read Services from Sheet', so $json
// is a spreadsheet ROW, not the tool-call data. The trigger holds the real
// input (service, vehicle, category) — read it from there.
const input = $('When Executed by Another Workflow').first().json || {};
const cfg = $('Business Config').first().json.business_config || {};
const currency = cfg.currency || 'CAD';
const disclaimer = cfg.estimate_disclaimer || 'Ballpark starting point only. Final time and price depend on inspection, parts availability, and shop approval.';

const year = (input.vehicleYear || input.year || '').toString().trim();
const make = (input.vehicleMake || input.make || '').toString().trim();
const model = (input.vehicleModel || input.model || '').toString().trim();
const serviceRaw = (input.service || input.request || input.serviceDetails || '').toString().trim();
const serviceCategory = (input.serviceCategory || '').toString().trim().toLowerCase();

// Load services from Google Sheet (live pricing) with fallback to Business Config
let services = [];
try {
  const sheetRows = $('Read Services from Sheet').all().map(i => i.json).filter(r => r.key);
  if (sheetRows.length > 0) {
    services = sheetRows.map(r => ({
      key: (r.key || '').toLowerCase().trim(),
      label: r.label || r.service_name || r.key,
      duration_minutes: parseInt(r.duration_minutes || r.duration || 90),
      starting_at: parseFloat(r.starting_at || r.price || 0)
    }));
  } else {
    services = cfg.services || [];
  }
} catch(e) {
  services = cfg.services || [];
}

// ── Guard 1: the AI called the tool without a service — tell it to retry ──
if (!serviceRaw && !serviceCategory) {
  return { json: {
    success: false,
    needsService: true,
    diagnosticOnly: false,
    estimatedMinutes: 0,
    startingAtPrice: '',
    startingAtText: '',
    serviceCategory: '',
    disclaimer,
    message: 'MISSING INPUT: the service field was empty. Call estimate_job_ballpark again and pass the service exactly as the customer described it (for example "front ball joint replacement"), plus vehicle year, make, and model.'
  }};
}

// ── Guard 2: services sheet failed to load — say so instead of silently defaulting ──
if (!services.length) {
  return { json: {
    success: false,
    servicesLoaded: 0,
    diagnosticOnly: false,
    estimatedMinutes: 90,
    startingAtPrice: '',
    startingAtText: '',
    serviceCategory: serviceCategory || '',
    disclaimer,
    message: `I can book you in for the ${serviceRaw || 'requested service'} on your ${year} ${make} ${model}, and the technician will confirm time and price at the shop. (Pricing sheet was unavailable for this call.)`
  }};
}

// Match service from input
function normaliseKey(str) {
  // Convert any variation to a comparable slug: spaces/hyphens -> underscore, lowercase
  return (str || '').toLowerCase().replace(/[\s\-]+/g, '_').replace(/[^a-z0-9_]/g, '').trim();
}


// ══════════════════════════════════════════════════════════════════
// Universal service matcher — stemmed token scoring
// No service-specific rules. Works for any row in the Services sheet.
//
// Algorithm:
//   Pass 0 — unambiguous keyword overrides (synthetic, rotor, front+rear brakes)
//   Pass 1 — exact normalised key match
//   Scoring — stem every word in the query; for each service score
//              key-token match = 2pts, label-token match = 1pt;
//              tiebreak by higher starting_at (more comprehensive service);
//              return best if score >= 2, else null.
//
// Key fix vs. old code:
//   • /s$/ runs BEFORE /es$/ → "axles"→"axle", "axle"→"axle" (consistent)
//   • Splits on [\W_]+ so "axle_replacement"→["axle","replacement"]
//   • Includes 2-char abbreviations (cv, ac, ps) in token set
//   • Negated words ("no rotor") removed from scoring set
// ══════════════════════════════════════════════════════════════════

const STOP = new Set([
  'and','or','the','for','with','from','each','per','this','that','both','new',
  'all','any','are','was','were','has','have','had','its','our','their',
  'at','be','by','do','go','is','it','me','my','no','of','on','so','to','up','us','we',
  'an','as','in','if','he','hi','ok','oh',
  'service','servicing','services','repair','repairs','fix','fixed','fixing',
  'need','needs','needed','want','wants','wanted','car','vehicle','truck',
  'please','some','something','look','looking','check','job','work','get','got',
]);

function keep(w) {
  return ((w.length === 2 && /^[a-z0-9]+$/.test(w) && /[a-z]/.test(w)) || w.length > 2) && !STOP.has(w);
}

function stem(w) {
  let prev;
  do {
    prev = w;
    w = w.replace(/ies$/, 'y')
         .replace(/tions?$/, 'te')
         .replace(/ments?$/, '')
         .replace(/ings?$/, '')
         .replace(/ness$/, '')
         .replace(/able$/, '')
         .replace(/ible$/, '')
         .replace(/ers?$/, '')
         .replace(/eds?$/, '')
         .replace(/s$/, '')     // s$ BEFORE es$ — "axles"→"axle", not "axl"
         .replace(/es$/, '');
  } while (w !== prev && w.length > 2);
  return w;
}

function matchService(key, category, rawText) {
  const search = [key, category, rawText].join(' ').toLowerCase();

  // ── Pass 0: unambiguous keyword overrides ────────────────────────
  const hasSynthetic = /\bsynthetic\b/i.test(search) && /\boil\b/i.test(search);
  const hasRotor     = /\brotor/i.test(search) && !/\b(?:no|not|without)\s+rotor/i.test(search);
  // Both-axle phrasing: front+rear, all around, all four, both axles, four rotors/wheels/corners
  const allAround    = /\b(?:front[\s\S]{0,20}rear|rear[\s\S]{0,20}front|all\s+(?:around|four)|both\s+axles?|four\s+(?:rotors?|wheels?|corners?))\b/i.test(search);
  // front+rear → brakes ONLY when brake context present (not for axle replacement)
  const hasFrontRear = allAround && /\bbrak/i.test(search);
  if (hasSynthetic) { const s = services.find(s => s.key === 'oil_change_synthetic'); if (s) return s; }
  if (hasRotor && allAround) {
    // All-four bundle if the sheet has it; per-axle row otherwise
    const s = services.find(s => s.key === 'brake_rotors_all') || services.find(s => s.key === 'brake_rotors');
    if (s) return s;
  }
  if (hasRotor)     { const s = services.find(s => s.key === 'brake_rotors');         if (s) return s; }
  if (hasFrontRear) { const s = services.find(s => s.key === 'brakes');               if (s) return s; }

  // ── Pass 1: exact normalised key match ───────────────────────────
  const normKey = normaliseKey(key);
  const normCat = normaliseKey(category);
  const exact = services.find(s =>
    s.key === normKey || s.key === normCat ||
    s.key === key     || s.key === category
  );
  if (exact) return exact;

  // ── Build stemmed search-word set; remove negated words ──────────
  const tokens = search.split(/[\W_]+/).filter(keep);
  const negated = new Set();
  for (const m of search.matchAll(/\b(?:no|not|without)\s+(\w+)/g)) {
    negated.add(stem(m[1]));
  }
  const searchWords = new Set(tokens.map(stem).filter(w => !negated.has(w)));

  // ── Scoring ───────────────────────────────────────────────────────
  // key word hit = 2pts. Core label word hit = 1pt (+2 rarity bonus when the
  // word appears in at most 2 services' key/core vocabulary — e.g. "axle" only
  // lives in the CV Joint / Axle Shaft row, so "replace front axles" finds it).
  // Qualifier words (after "–" or in parentheses, like "– Front" or
  // "(per axle)") = 1pt, no rarity bonus — they describe scope, not the part.
  function splitLabel(label) {
    const parts = String(label || '').toLowerCase().split(/\s[–—]\s|\s-\s|\(/);
    const core = (parts.shift() || '');
    const qual = parts.join(' ');
    return {
      core: core.split(/[\W_]+/).filter(keep).map(stem),
      qual: qual.split(/[\W_]+/).filter(keep).map(stem)
    };
  }
  // Document frequency over key + core-label words only
  const docFreq = {};
  for (const svc of services) {
    const l = splitLabel(svc.label);
    const ws = new Set([...svc.key.split('_').filter(keep).map(stem), ...l.core]);
    for (const w of ws) docFreq[w] = (docFreq[w] || 0) + 1;
  }
  let bestScore = 0, bestMatch = null;
  for (const svc of services) {
    const l = splitLabel(svc.label);
    const keyWords = svc.key.split('_').filter(keep).map(stem);
    let score = 0;
    const bonused = new Set();
    for (const w of keyWords) if (searchWords.has(w)) {
      score += 2;
      if ((docFreq[w] || 0) <= 2 && !bonused.has(w)) { score += 2; bonused.add(w); }
    }
    for (const w of l.core) if (searchWords.has(w)) {
      score += 1;
      if ((docFreq[w] || 0) <= 2 && !bonused.has(w)) { score += 2; bonused.add(w); }
    }
    for (const w of l.qual) if (searchWords.has(w)) score += 1;
    if (score > bestScore || (score === bestScore && bestMatch && svc.starting_at > bestMatch.starting_at)) {
      bestScore = score;
      bestMatch = svc;
    }
  }
  return bestScore >= 2 ? bestMatch : null;
}


// Only use diagnostic routing for symptoms with NO identifiable service.
// If the customer names a specific job (ball joint, timing belt, etc.),
// book them for that — not for a diagnostic.
const symptomOnlyKeywords = /check.?engine|overheating|electrical.?issue|strange.?noise|weird.?noise|something.?wrong|not.?sure|i.?don.?t.?know|making.?noise|runs.?rough|stall|shudder/i;
const namedServiceKeywords = /brake|oil.?change|oil.?pan|tire|wheel|bearing|joint|belt|fluid|filter|alignment|suspension|exhaust|battery|alternator|starter|spark|plug|coolant|radiator|clutch|transmission.?fluid|differential|axle|cv.?joint|strut|shock|caliper|rotor|pad|tie.?rod|control.?arm|sway.?bar|ball.?joint|cv.?boot|u.?joint|muffler|catalytic|o2.?sensor|oxygen.?sensor|head.?gasket|timing|water.?pump|thermostat|alternator|valve.?cover|engine.?mount|heater.?core|ac.?compressor|power.?steering|abs/i;

// Route to diagnostic only when it's a vague symptom AND no named service is identifiable
const isVagueSymptom = symptomOnlyKeywords.test(serviceRaw) || symptomOnlyKeywords.test(serviceCategory);
const hasNamedService = namedServiceKeywords.test(serviceRaw) || namedServiceKeywords.test(serviceCategory);
const diagnosticOnly = isVagueSymptom && !hasNamedService;

if (diagnosticOnly) {
  const diag = matchService('diagnostic', 'diagnostic', 'diagnostic') || { starting_at: 120, duration_minutes: 60, label: 'Diagnostic' };
  return { json: {
    diagnosticOnly: true,
    estimatedMinutes: diag.duration_minutes,
    startingAtPrice: diag.starting_at,
    startingAtText: `$${diag.starting_at} ${currency} and up`,
    serviceCategory: 'diagnostic',
    disclaimer,
    message: `For that kind of issue we'd recommend starting with a diagnostic to find out what's going on. The technician will confirm pricing after inspecting the vehicle.`
  }};
}

const matched = matchService(serviceCategory, serviceCategory, serviceRaw);

if (matched) {
  return { json: {
    diagnosticOnly: false,
    estimatedMinutes: matched.duration_minutes,
    startingAtPrice: matched.starting_at,
    startingAtText: `$${matched.starting_at} ${currency} and up`,
    serviceCategory: matched.key,
    serviceLabel: matched.label,
    disclaimer,
    message: `Got it — a ${matched.label.toLowerCase()} for a ${year} ${make} ${model} usually takes about ${matched.duration_minutes} minutes${matched.starting_at > 0 ? `, starting around $${matched.starting_at} ${currency}` : ''}. That's a rough starting point — the technician will confirm the final price after inspecting the vehicle. Would you like to book an appointment?`
  }};
}

// Service not in sheet — book for the actual named service, NOT a diagnostic.
// Customer knows what they want; we just can't quote a price yet.
const serviceLabel = serviceRaw || serviceCategory || 'the requested service';
return { json: {
  diagnosticOnly: false,
  estimatedMinutes: 90,
  startingAtPrice: 0,
  startingAtText: '',
  serviceCategory: serviceCategory || 'repair',
  serviceLabel,
  disclaimer,
  message: `We can book you in for the ${serviceLabel} on your ${year} ${make} ${model}. The technician will inspect the vehicle first and confirm the exact time and price before starting any work — there is no separate diagnostic charge for a repair visit. Would you like to book an appointment?`
}};

const inp = $input.first().json || {};
let p = {};
try { p = $('Estimate Job Ballpark').first().json || {}; } catch(e) {}

const result = Object.keys(p).length > 0 ? p : inp;


// FIX #5: fallback=true when service was not found in sheet and diagnostic default was used
const _isFallback = !!(result.diagnosticOnly === true && !inp.serviceCategory);
return { json: {
  fallback: _isFallback,
  success: true,
  diagnosticOnly: result.diagnosticOnly || false,
  estimatedMinutes: result.estimatedMinutes || 90,
  startingAtPrice: result.startingAtPrice || '',
  startingAtText: result.startingAtText || '',
  serviceCategory: result.serviceCategory || '',
  disclaimer: result.disclaimer || 'Ballpark starting point only. Final time and price depend on inspection.',
  message: result.message || ''
}};

// Fast path: build dynamic_variables from webhook data only (no Sheets I/O).
// This must complete within ElevenLabs' webhook timeout (~5s).
// Business Config is inlined here because this node runs in the setVar webhook
// chain where Business Config node has NOT been executed.
const set1 = $('Set1').first().json || {};
const callerPhone = set1.phone || '';
const callSid = set1.call_sid || '';

// Business Config - Init runs just before this node in the setVar chain.
const _cfg = $('Business Config - Init').first().json.business_config || {};
const businessName = _cfg.name || 'our auto repair shop';
const ownerPhone   = _cfg.owner_phone || '';
const timezone     = _cfg.timezone || 'America/Toronto';

// Human-readable business hours for the AI — single source of truth for
// "are you open on X?" questions. Prevents hallucinated hours.
function humanHours(oh) {
  const m = String(oh || '').match(/(\d{1,2}):(\d{2})\s*-\s*(\d{1,2}):(\d{2})/);
  if (!m) return oh || '9 AM to 5 PM';
  const fmt = (h, mm) => { h = Number(h); const p = h >= 12 ? 'PM' : 'AM'; const d = h % 12 || 12; return mm === '00' ? `${d} ${p}` : `${d}:${mm} ${p}`; };
  return `${fmt(m[1], m[2])} to ${fmt(m[3], m[4])}`;
}
function humanDays(od) {
  const names = { mon:'Monday', tue:'Tuesday', wed:'Wednesday', thu:'Thursday', fri:'Friday', sat:'Saturday', sun:'Sunday' };
  const m = String(od || '').toLowerCase().match(/([a-z]{3})[a-z]*\s*-\s*([a-z]{3})/);
  if (m && names[m[1]] && names[m[2]]) return `${names[m[1]]} to ${names[m[2]]}`;
  return od || 'Monday to Friday';
}
const operatingDaysText = humanDays(_cfg.operating_days);
const businessHours = `${operatingDaysText}, ${humanHours(_cfg.opening_hours)}`;

function tod() {
  const h = DateTime.now().setZone(timezone).hour;
  if (h < 12) return 'morning';
  if (h < 17) return 'afternoon';
  return 'evening';
}

const baseRules = `## Rules
You are a receptionist for ${businessName}. Be fast, concise, warm, and professional.
Ask year/make/model in ONE question: "What's the year, make, and model?"
Give only rough ballpark starting points. Never give exact, precise, guaranteed, final, or locked-in quotes.
Every price or time estimate must be framed as a rough starting point, and the technician must confirm final details after inspecting the vehicle.
BUSINESS HOURS: We are open ${businessHours}. This is the ONLY source of truth for hours. Never invent or guess hours. If a caller asks about a day outside ${operatingDaysText}, tell them we are closed that day and offer the next open day instead.`;

const dynamic_variables = {
  first_message: `Good ${tod()}, thanks for calling ${businessName}. How can I help with your vehicle today?`,
  caller_phone: callerPhone,
  business_hours: businessHours,
  call_sid: callSid,
  agent_mode: 'new_auto_repair_booking',
  owner_phone: ownerPhone,
  customer_name: '',
  appointment_id: '',
  agent_instructions: `${baseRules}

## Flow
Get the vehicle and service/problem first.
Offer rough starting-point estimates only when asked.
Offer to book after understanding the issue.
Collect first name and phone number only when booking. Never ask for last name.
When the caller wants to reschedule or cancel: say "Just a second, let me check that for you." then immediately call lookup_customer using caller_phone. Never ask the caller for their phone number or appointment ID first. Only ask for their phone number if lookup_customer returns no result. After lookup_customer succeeds, address the caller by name and confirm the found appointment: say something like "Okay [Name], I found your appointment for [date] at [time]. When would you like to reschedule it to?"

## Silence Handling — follow exactly
Step 1 — first silence: Say only "Are you still there?" then stop and wait.
Step 2 — silence continues: Say "I'm sorry, I'm having trouble hearing you. Feel free to call us back whenever you're ready. Have a great day!" then IMMEDIATELY call end_call with reason "caller_silent". Never repeat the farewell. Never skip end_call after it.

## End Call
Always call end_call after a farewell when: caller silent after two prompts, conversation naturally concluded, caller abusive, or robocall. Saying goodbye alone does not end the call — end_call is required.`
};

return { json: { dynamic_variables } };

// Return booking success — reads from input (Update SMS sent status node passes through)
// Falls back to Prepare Booking Payload if available
let p = {};
try { p = $('Prepare Booking Payload').first().json || {}; } catch(e) {}

// Also try reading from current input item
const inp = $input.first().json || {};

const appointmentDate = p.appointmentDate || inp.appointmentDate || '';
const appointmentTime = p.appointmentTime || inp.appointmentTime || '';
const customerName = p.customerName || inp.customerName || '';
const vehicle = p.vehicle || [p.vehicleYear, p.vehicleMake, p.vehicleModel].filter(Boolean).join(' ') || '';
const service = p.service || inp.service || '';

return {
  json: {
