const callsList = $('Twilio - Redirect Call to Owner').first().json || {};
const updateResp = $('Twilio - Update Call With Transfer TwiML').first().json || {};

// Check if we found an active call
const activeCalls = callsList.calls || [];
const foundCall = activeCalls.length > 0;

// Check if the update succeeded
const updateSid = updateResp.sid || '';
const updateError = updateResp.code || updateResp.error || updateResp.message || '';
const transferOk = foundCall && updateSid && !updateError;

return { json: {
  success: transferOk,
  transfer_initiated: transferOk,
  message: transferOk
    ? "I'm connecting you now — please hold for just a moment."
    : "I wasn't able to reach the team right now. Can I get your name and best number so someone can call you back?",
  needs_callback: !transferOk,
  caller_phone: ctx.callerPhone,
  caller_name: ctx.callerName,
  reason: ctx.reason,
  debug_activeCalls: activeCalls.length,
  debug_foundCallSid: activeCalls[0]?.sid || 'none',
  debug_updateSid: updateSid,
  debug_updateError: updateError
}};

// Twilio sends DialCallStatus: 'completed', 'no-answer', 'busy', 'failed', 'canceled'
const body = $json.body || $json || {};
const dialStatus = body.DialCallStatus || body.dial_call_status || 'unknown';
const callSid    = body.CallSid || body.call_sid || '';
const callerNum  = body.From || body.from || body.Caller || '';
const answered   = dialStatus === 'completed';

return { json: {
  dialStatus,
  callSid,
  callerNum,
  answered,
  needsCallback: !answered,
  timestamp: $now.toISO()
}};

// Owner answered — Twilio already bridged the call.
// Return empty TwiML to close out the action callback.
return { json: { twiml: '<Response></Response>', status: 'connected' }};

// Owner did not answer. Play a message and collect caller's name via Twilio <Gather>.
const cb = $json || {};
const twiml = `<Response>
  <Say voice="alice">I'm sorry, our team is unavailable right now. Please leave your name after the tone and we will call you back as soon as possible.</Say>
  <Record timeout="10" maxLength="30" action="https://n8n.srv1320343.hstgr.cloud/webhook/handoff-recording" method="POST" playBeep="true"/>
  <Say voice="alice">Thank you. We will call you back shortly. Goodbye.</Say>
  <Hangup/>
</Response>`;
return { json: { twiml, callerNum: cb.callerNum, callSid: cb.callSid, timestamp: cb.timestamp }};

function formatPhoneForSheet(phone) {
  if (!phone) return '';
  const digits = String(phone).replace(/[^\d]/g, '');
  if (digits.length === 11 && digits.startsWith('1')) return digits.slice(1);
  if (digits.length === 10) return digits;
  return digits;
}
const body = $json.body || $json || {};
const data = body.data || {};
const analysis = data.analysis || {};
const metadata = data.metadata || {};
const convInit = data.conversation_initiation_client_data || {};
const dynamicVars = convInit.dynamic_variables || {};

const callerPhone = formatPhoneForSheet(dynamicVars.caller_phone || dynamicVars.caller_id || metadata.phone_number || '');
const conversationId = data.conversation_id || '';

// Read the call_summary data collection field configured in ElevenLabs Analysis tab
const dataCollection = analysis.data_collection_results || {};
const notesText = dataCollection.call_summary?.value
  || dataCollection.call_summary
  || analysis.transcript_summary
  || 'Call completed';

return { json: {
  conversationId,
  callerPhone,
  notesText,
  timestamp: $now.toISO()
}};

// Find appointments starting in 24h (within a 30-minute window to avoid duplicates).
// Also skips appointments booked less than 2 hours ago — the customer just
// confirmed, so an immediate reminder is redundant and confusing.
const cfg = $('Business Config - Reminder').first().json.business_config || {};
const tz = cfg.timezone || 'America/Toronto';

const now = DateTime.now().setZone(tz);
const windowStart = now.plus({ hours: 23, minutes: 30 });
const windowEnd   = now.plus({ hours: 24, minutes: 30 });
const recentCutoff = now.minus({ hours: 2 }); // skip if booked within last 2 hours

const rows = $input.all().map(i => i.json);
const due = rows.filter(row => {
  if (!row['Appointment Start']) return false;

  // Skip cancelled, completed, etc — only remind booked or rescheduled
  const st = (row['Status'] || '').toLowerCase();
  if (st !== 'booked' && st !== 'rescheduled') return false;

  // Skip if reminder already sent
  if ((row['Reminder Sent'] || '').toLowerCase() === 'yes') return false;

  // Skip if phone is missing — can't send SMS
  if (!(row['Phone'] || '').toString().replace(/\D/g,'')) return false;

  // Parse appointment start time
  let apptTime = DateTime.fromFormat(
    row['Appointment Start'],
    'ccc, LLL d, yyyy h:mm a',
    { zone: tz }
  );
  if (!apptTime.isValid) {
    apptTime = DateTime.fromISO(row['Appointment Start'], { zone: tz });
  }
  if (!apptTime.isValid) return false;

  // Must be in the 24h window
  if (!(apptTime >= windowStart && apptTime <= windowEnd)) return false;

  // Skip if booked less than 2 hours ago (customer just confirmed — no reminder needed yet).
  // Uses Created At column; if missing, allow the reminder through.
  if (row['Created At']) {
    let bookedAt = DateTime.fromFormat(row['Created At'], 'ccc, LLL d, yyyy h:mm a', { zone: tz });
    if (!bookedAt.isValid) bookedAt = DateTime.fromISO(row['Created At'], { zone: tz });
    if (bookedAt.isValid && bookedAt > recentCutoff) return false;
  }

  return true;
});

return due.map(row => ({ json: row }));

// Webhook secret validation — warn only, never block.
// Blocking causes Set1 to not run, which means phone is never stored.
// Secret is inlined because Business Config is not in the setVar chain.
const WEBHOOK_SECRET = 'aheJMv1URiPk-cRnRmeo_uG1yJpWviqYWy4zXFOw6lo';
const incoming = ($json.headers || {})['x-webhook-secret'] || '';
const isValid = !WEBHOOK_SECRET || WEBHOOK_SECRET === 'CHANGE_ME_TO_A_RANDOM_SECRET' || incoming === WEBHOOK_SECRET;
return [{ json: { ...$json, _webhookSecretValid: isValid, _webhookSecretWarning: isValid ? null : 'Invalid webhook secret' } }];

