// FIX #3: Verify new reschedule event was created before deleting the old one.
// If create failed, old appointment is untouched and caller is informed.
const result = $input.first().json || {};
const eventId = result.id || result.eventId || result.calendarEventId || '';
const hasError = !!(result.error || result.code);
const createOk = !hasError && !!(eventId || result.start);
let c4 = {};
try { c4 = $('Code4').first().json || {}; } catch(e) {}
return [{ json: { ...c4, newCalendarEventId: eventId, createOk, createResult: result } }];

const inp = $input.first().json || {};
return [{ json: {
  success: false,
  rescheduled: false,
  message: 'Could not create the new appointment slot. Your original appointment was NOT cancelled. Please try again or call us.',
  note: 'Atomic reschedule guard: old event preserved because new event creation failed.'
} }];

let trigger = {};
try { trigger = $('When Executed by Another Workflow').first().json || {}; } catch(e) {}

let cfg = {};
try { cfg = $('Business Config').first().json.business_config || {}; } catch(e) {}

let callSid = '';

// 1. PRIMARY: Sessions Google Sheet
try {
  const rows = $('Read Sessions For End Call').all()
    .map(r => r.json)
    .filter(r => r.call_sid && /^CA[a-f0-9]{32}$/i.test(r.call_sid))
    .sort((a, b) => new Date(b.stored_at || 0) - new Date(a.stored_at || 0));
  if (rows.length > 0) callSid = rows[0].call_sid || '';
} catch(e) {}

// 2. SECONDARY: n8n workflow static data
if (!callSid) {
  try {
    const sd = $getWorkflowStaticData('global');
    if (sd.call_sid && sd.stored_at && (Date.now() - sd.stored_at) < 7200000) {
      callSid = sd.call_sid;
    }
  } catch(e) {}
}

// 3. LAST RESORT: trigger payload
if (!callSid) callSid = trigger.call_sid || trigger.system__call_sid || '';

// accountSid: try Business Config first, then Twilio credential
let accountSid = cfg.twilio_account_sid || '';
if (!accountSid) {
  try { accountSid = $credentials.twilioApi?.accountSid || ''; } catch(e) {}
}

const reason = trigger.reason || 'unknown';
const isValidSid = /^CA[a-f0-9]{32}$/i.test(callSid);

// canEnd only requires a valid callSid — accountSid is handled by the credential
return [{ json: { callSid, accountSid, reason, isValidSid, canEnd: isValidSid, timestamp: $now.toISO() } }];

