// Find any existing BOOKED appointment for this customer's phone.
// If found, extract its old Calendar Event ID so we can delete it
// and overwrite the sheet row instead of creating a duplicate.
const payload = $('Prepare Booking Payload').first().json;
const phone = (payload.customerPhone || '').replace(/\D/g, '');
const rows = $input.all().map(r => r.json);
let oldCalendarEventId = '';
let oldAppointmentId = '';
if (phone) {
  const existing = rows.find(r => {
    const rowPhone = (r.Phone || '').replace(/\D/g, '');
    return rowPhone === phone && (r.Status || '').toLowerCase() === 'booked';
  });
  if (existing) {
    oldCalendarEventId = existing['Calendar Event ID'] || '';
    oldAppointmentId   = existing['Appointment ID'] || '';
  }
}
return [{ json: { ...payload, oldCalendarEventId, oldAppointmentId } }];

// Calendar delete changed $json to the API response.
// Restore the booking payload so Append row in sheet1 sees correct fields.
const p = $('Extract Old Event ID').first().json;
return [{ json: p }];

// Keep only session rows older than 2 hours.
// Sessions are only needed during the call itself — 2h is a safe TTL.
// stored_at may be ISO ('2026-06-09T16:12+02:00') or human-readable
// ('Mon, Jun 9, 2026 4:12 PM') — handle both.
const cutoff = DateTime.now().minus({ hours: 2 });
const rows = $input.all().map(r => r.json);
const old = rows.filter(row => {
  if (!row.call_sid) return false;
  if (!row.stored_at) return true;
  try {
    // Try ISO first
    let t = DateTime.fromISO(row.stored_at);
    // Fall back to human-readable format used by new entries
    if (!t.isValid) {
      t = DateTime.fromFormat(row.stored_at, 'ccc, LLL d, yyyy h:mm a',
            { zone: 'America/Toronto' });
    }
    return t.isValid && t < cutoff;
  } catch(e) { return true; }
});
// Sort descending by row_number so we delete from bottom up.
old.sort((a, b) => (b.row_number || 0) - (a.row_number || 0));
return old.map(r => ({ json: r }));

// Write call_sid and caller_phone to n8n workflow static data.
// This is the ONLY place these values are persisted for later tool calls
// (end_call reads from static data — Google Sheets is too slow for that path).
const inp = $input.first().json || {};
const sid   = inp.call_sid   || '';
const phone = inp.phone      || '';
try {
  if (sid) {
    const sd = $getWorkflowStaticData('global');
    sd.call_sid     = sid;
    sd.caller_phone = phone;
    sd.stored_at    = Date.now();
  }
} catch(e) {}
return [$input.first()];
